import{_ as a,c as e,o as n,a1 as i}from"./chunks/framework.DILC4Csi.js";const m=JSON.parse('{"title":"Início Rápido: Introdução ao Plannotator | plannotator","description":"Aprenda o método de início rápido do Plannotator. Entenda as funcionalidades principais em 5 minutos e complete a instalação e configuração do plugin Claude Code ou OpenCode.","frontmatter":{"title":"Início Rápido: Introdução ao Plannotator | plannotator","sidebarTitle":"Introdução em 5 Minutos","subtitle":"Início Rápido: Introdução ao Plannotator","description":"Aprenda o método de início rápido do Plannotator. Entenda as funcionalidades principais em 5 minutos e complete a instalação e configuração do plugin Claude Code ou OpenCode.","order":1},"headers":[],"relativePath":"pt/backnotprop/plannotator/start/index.md","filePath":"pt/backnotprop/plannotator/start/index.md"}'),t={name:"pt/backnotprop/plannotator/start/index.md"};function d(r,o,l,s,p,c){return n(),e("div",null,[...o[0]||(o[0]=[i('<h1 id="inicio-rapido" tabindex="-1">Início Rápido <a class="header-anchor" href="#inicio-rapido" aria-label="Permalink to &quot;Início Rápido&quot;">​</a></h1><p>Este capítulo ajuda você a começar a usar o Plannotator do zero. Você entenderá o que é o Plannotator, quais problemas ele resolve e completará a instalação e configuração no seu AI Coding Agent (Claude Code ou OpenCode).</p><h2 id="conteudo-do-capitulo" tabindex="-1">Conteúdo do Capítulo <a class="header-anchor" href="#conteudo-do-capitulo" aria-label="Permalink to &quot;Conteúdo do Capítulo&quot;">​</a></h2><div class="grid-cards"><h3 id="inicio-rapido-1" tabindex="-1"><a href="./getting-started/">Início Rápido</a> <a class="header-anchor" href="#inicio-rapido-1" aria-label="Permalink to &quot;[Início Rápido](./getting-started/)&quot;">​</a></h3><p>Entenda as funcionalidades principais e cenários de uso do Plannotator, e complete sua primeira experiência em 5 minutos. Adequado como primeira aula de introdução para todos os novos usuários.</p><h3 id="instalar-plugin-claude-code" tabindex="-1"><a href="./installation-claude-code/">Instalar Plugin Claude Code</a> <a class="header-anchor" href="#instalar-plugin-claude-code" aria-label="Permalink to &quot;[Instalar Plugin Claude Code](./installation-claude-code/)&quot;">​</a></h3><p>Instale e configure o plugin Plannotator no Claude Code, suportando dois métodos: sistema de plugins e Hook manual, cobrindo configuração de ambientes locais e remotos.</p><h3 id="instalar-plugin-opencode" tabindex="-1"><a href="./installation-opencode/">Instalar Plugin OpenCode</a> <a class="header-anchor" href="#instalar-plugin-opencode" aria-label="Permalink to &quot;[Instalar Plugin OpenCode](./installation-opencode/)&quot;">​</a></h3><p>Instale e configure o plugin Plannotator no OpenCode, ativando a ferramenta <code>submit_plan</code> e o comando <code>/plannotator-review</code>.</p></div><h2 id="caminho-de-aprendizado" tabindex="-1">Caminho de Aprendizado <a class="header-anchor" href="#caminho-de-aprendizado" aria-label="Permalink to &quot;Caminho de Aprendizado&quot;">​</a></h2><div class="tip custom-block"><p class="custom-block-title">Sequência Recomendada</p><ol><li><strong>Primeiro leia <a href="./getting-started/">Início Rápido</a></strong>: Entenda o que é o Plannotator, o que ele pode fazer, e estabeleça uma compreensão geral</li><li><strong>Depois escolha um tutorial de instalação</strong>: Selecione o guia de instalação correspondente baseado no AI Coding Agent que você usa <ul><li>Usando Claude Code → <a href="./installation-claude-code/">Instalar Plugin Claude Code</a></li><li>Usando OpenCode → <a href="./installation-opencode/">Instalar Plugin OpenCode</a></li></ul></li></ol></div><p>Após completar a instalação, você pode começar a usar o Plannotator para revisão de planos e revisão de código.</p><h2 id="proximos-passos" tabindex="-1">Próximos Passos <a class="header-anchor" href="#proximos-passos" aria-label="Permalink to &quot;Próximos Passos&quot;">​</a></h2><p>Após completar este capítulo, continue aprendendo <strong><a href="./../platforms/">Funcionalidades da Plataforma</a></strong> para dominar o uso completo de revisão de planos e revisão de código:</p><ul><li>Fundamentos de revisão de planos: aprovar, rejeitar, adicionar comentários</li><li>Anotação de imagens: anexar capturas de tela nos planos e adicionar anotações</li><li>Revisão de código: visualizar Git diff, adicionar comentários de nível de linha</li></ul>',10)])])}const h=a(t,[["render",d]]);export{m as __pageData,h as default};
